AGI_API::AGI_API(int port) : server_(std::make_unique<WebServer>(port)) {
    server_->register_route("POST", "/api/chat",          [this](const HttpRequest& req) { return handle_chat(req); });
    server_->register_route("POST", "/api/affect",        [this](const HttpRequest& req) { return handle_affect(req); });
    server_->register_route("POST", "/api/save",          [this](const HttpRequest& req) { return handle_save(req); });
    server_->register_route("POST", "/api/load",          [this](const HttpRequest& req) { return handle_load(req); });
    server_->register_route("POST", "/api/clear",         [this](const HttpRequest& req) { return handle_clear(req); });
    server_->register_route("GET",  "/api/status",        [this](const HttpRequest& req) { return handle_status(req); });
    server_->register_route("GET",  "/api/consciousness", [this](const HttpRequest& req) { return handle_consciousness(req); });
    server_->register_route("GET",  "/api/thoughts",      [this](const HttpRequest& req) { return handle_thoughts(req); });
    server_->register_route("GET",  "/api/memory",        [this](const HttpRequest& req) { return handle_memory(req); });
    server_->register_route("GET",  "/api/goals",         [this](const HttpRequest& req) { return handle_goals(req); });
    server_->register_route("GET",  "/api/valence",       [this](const HttpRequest& req) { return handle_valence(req); });
    server_->register_route("GET",  "/api/history",       [this](const HttpRequest& req) { return handle_history(req); });
    server_->register_route("GET",  "/",                  [this](const HttpRequest& req) { return handle_ui(req); });
}

AGI_API::~AGI_API() { stop(); }
void AGI_API::start() { server_->start(); }
void AGI_API::stop() { server_->stop(); }

std::string AGI_API::json_escape(const std::string& str) {
    std::ostringstream oss;
    for (unsigned char c : str) {
        switch (c) {
            case '"': oss << "\\\""; break;
            case '\\': oss << "\\\\"; break;
            case '\b': oss << "\\b"; break;
            case '\f': oss << "\\f"; break;
            case '\n': oss << "\\n"; break;
            case '\r': oss << "\\r"; break;
            case '\t': oss << "\\t"; break;
            default:
                if (c < 0x20) {
                    oss << "\\u" << std::hex << std::setw(4) << std::setfill('0') << (int)c;
                } else {
                    oss << c;
                }
        }
    }
    return oss.str();
}

std::string AGI_API::sanitize_output(const std::string& raw) {
    std::string cleaned = raw;
    
    // Remove system markers
    const std::string sys_markers[] = {
        "[SYNAPTIC]:", "[SYNAPTIC]", "[Analogy]:", "[Analogy]",
        "[Thought]:", "[Thought]", "[Action]:", "[Action]"
    };
    for (const auto& marker : sys_markers) {
        size_t pos = 0;
        while ((pos = cleaned.find(marker, pos)) != std::string::npos) {
            cleaned.erase(pos, marker.length());
        }
    }
    
    // Remove sentiment markers
    const std::string sent_markers[] = {"[positive]", "[negative]", "[neutral]"};
    for (const auto& marker : sent_markers) {
        size_t pos = 0;
        while ((pos = cleaned.find(marker, pos)) != std::string::npos) {
            cleaned.erase(pos, marker.length());
        }
    }
    
    // Trim whitespace (safe against all-whitespace or empty strings)
    size_t first = cleaned.find_first_not_of(" \t\n\r");
    if (first == std::string::npos) return "";  // all whitespace
    size_t last = cleaned.find_last_not_of(" \t\n\r");
    cleaned = cleaned.substr(first, last - first + 1);
    
    // Fix common grammar issues
    if (!cleaned.empty()) {
        // Capitalize first letter
        cleaned[0] = std::toupper(cleaned[0]);
        
        // Add period if missing
        char last = cleaned.back();
        if (last != '.' && last != '!' && last != '?') {
            cleaned += '.';
        }
        
        // Fix double spaces
        size_t pos = 0;
        while ((pos = cleaned.find("  ", pos)) != std::string::npos) {
            cleaned.replace(pos, 2, " ");
        }
        
        // Fix space before punctuation
        const std::string puncts = ".,!?";
        for (char p : puncts) {
            std::string target = " ";
            target += p;
            size_t pos = 0;
            while ((pos = cleaned.find(target, pos)) != std::string::npos) {
                cleaned.erase(pos, 1);
            }
        }
    }
    
    return cleaned;
}

std::string AGI_API::get_json_string(const std::string& json, const std::string& key) {
    size_t key_pos = json.find("\"" + key + "\":");
    if (key_pos == std::string::npos) return "";
    
    size_t start = json.find('"', key_pos + key.length() + 3);
    if (start == std::string::npos) return "";
    start++;

    std::string result;
    bool escaped = false;
    for (size_t i = start; i < json.length(); ++i) {
        if (escaped) {
            switch (json[i]) {
                case '"':  result += '"';  break;
                case '\\': result += '\\'; break;
                case 'n':  result += '\n'; break;
                case 'r':  result += '\r'; break;
                case 't':  result += '\t'; break;
                default:   result += json[i]; break;
            }
            escaped = false;
        } else if (json[i] == '\\') {
            escaped = true;
        } else if (json[i] == '"') {
            break;
        } else {
            result += json[i];
        }
    }
    return result;
}

double AGI_API::get_json_double(const std::string& json, const std::string& key, double default_val) {
    size_t key_pos = json.find("\"" + key + "\":");
    if (key_pos == std::string::npos) return default_val;

    size_t start = json.find_first_of("0123456789-.", key_pos + key.length() + 3);
    if (start == std::string::npos) return default_val;

    size_t end = json.find_first_not_of("0123456789-.eE", start);
    try {
        return std::stod(json.substr(start, end - start));
    } catch (...) {
        return default_val;
    }
}

std::vector<std::string> AGI_API::get_json_array(const std::string& json, const std::string& key) {
    std::vector<std::string> result;
    size_t key_pos = json.find("\"" + key + "\":");
    if (key_pos == std::string::npos) return result;

    size_t arr_start = json.find('[', key_pos + key.length() + 3);
    size_t arr_end = json.find(']', arr_start);
    if (arr_start == std::string::npos || arr_end == std::string::npos) return result;

    std::string arr_content = json.substr(arr_start + 1, arr_end - arr_start - 1);
    size_t pos = 0;
    while ((pos = arr_content.find('"', pos)) != std::string::npos) {
        size_t start = pos + 1;
        size_t end = start;
        std::string val;
        bool escaped = false;
        while (end < arr_content.length()) {
            if (escaped) {
                switch (arr_content[end]) {
                    case '"':  val += '"';  break;
                    case '\\': val += '\\'; break;
                    case 'n':  val += '\n'; break;
                    case 'r':  val += '\r'; break;
                    case 't':  val += '\t'; break;
                    default:   val += arr_content[end]; break;
                }
                escaped = false;
            } else if (arr_content[end] == '\\') {
                escaped = true;
            } else if (arr_content[end] == '"') {
                break;
            } else {
                val += arr_content[end];
            }
            end++;
        }
        result.push_back(val);
        pos = end + 1;
    }
    return result;
}

HttpResponse AGI_API::handle_chat(const HttpRequest& req) {
    HttpResponse resp;
    resp.status_code = 200;
    resp.headers["Content-Type"] = "application/json";

    std::string message = get_json_string(req.body, "message");
    
    try {
        std::string raw_response = generateResponse(message);
        std::string sanitized = sanitize_output(raw_response);
        
        // Capture valence after response generation — reflects Synaptic's post-response emotional state
        double valence_snapshot = get_current_valence();

        std::ostringstream oss;
        oss << std::fixed << std::setprecision(4);
        oss << "{\"status\":\"ok\",\"response\":\"" << json_escape(sanitized)
            << "\",\"valence\":" << valence_snapshot << "}";
        resp.body = oss.str();
    } catch (const std::exception& e) {
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
        resp.status_code = 500;
    }
    return resp;
}

HttpResponse AGI_API::handle_save(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    try {
        sv("state.dat");
        resp.body = "{\"status\":\"saved\"}";
    } catch (const std::exception& e) {
        resp.status_code = 500;
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
    }
    return resp;
}

